import{_ as a,c as t,o as r,ai as n}from"./chunks/framework.BUcsHFk8.js";const h=JSON.parse('{"title":"New Research Paper","description":"","frontmatter":{"title":"New Research Paper","date":"2025-10-27","banner":"assets/blog/20251027_sap_cloud_infrastructure_dataset_paper_banner.svg","authors":["NeoNephos Team"],"tags":["2025","news","paper","dataset"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20251119_sap_cloud_infrastructure_dataset_paper.md","filePath":"blog/20251119_sap_cloud_infrastructure_dataset_paper.md"}'),o={name:"blog/20251119_sap_cloud_infrastructure_dataset_paper.md"};function s(i,e,d,p,l,c){return r(),t("div",null,e[0]||(e[0]=[n('<h1 id="new-research-paper" tabindex="-1">New Research Paper <a class="header-anchor" href="#new-research-paper" aria-label="Permalink to &quot;New Research Paper&quot;">​</a></h1><p>Efficient scheduling of virtual machines, their associated workloads and the underlying infrastructure itself is an active research topic of fundamental importance for infrastructure providers. Because the workload characteristics (and their temporal evolution) are distinct to each datacenter and may involve multiple coprocessors, efficient provisioning is difficult and subject to one&#39;s unique constraints. The new &quot;The SAP Cloud Infrastructure Dataset: A Reality Check of Scheduling and Placement of VMs in Cloud Computing&quot; sheds light on this situation, by providing and analyzing telemetry data from 1,800 hypervisors and 48,000 Virtual Machines (VMs), which are part of the SAP Cloud Infrastructure, over a 30-day observation period. It was created as a collaboration between SAP and the TU Dresden. Additionally, Arno Uhlig, Engineering Manager at SAP and member of our CobaltCore project, presented the paper at the <a href="https://tu-dresden.de/ing/informatik/sya/netd/about/events/acm-imc-2025?set_language=en" target="_blank" rel="noreferrer">ACM Internet Measurement Conference 2025</a>, a prestigious and known venue in this domain.</p><p>Get the paper here: <a href="https://arxiv.org/pdf/2510.23911" target="_blank" rel="noreferrer">https://arxiv.org/pdf/2510.23911</a></p><p>To learn more about this topic, <a href="https://github.com/cobaltcore-dev" target="_blank" rel="noreferrer">follow the CobaltCore team</a> for updates and try their Cortex scheduler if you want to immerse yourself even deeper!</p>',4)]))}const f=a(o,[["render",s]]);export{h as __pageData,f as default};
